// Solution
function validatePortMappings(portMappings) {
    let containerPorts = new Set();
    for (let mapping of portMappings) {
        let [containerPort, hostPort] = mapping.split(':');
        let hostPortNum = parseInt(hostPort);
        if (containerPort > 65535 || hostPortNum > 65535) {
            return false;
        }
        if (containerPorts.has(containerPort) && parseInt(containerPort) !== hostPortNum) {
            return false;
        }
        containerPorts.add(containerPort);
    }
    return true;
}

