class Solution:
    def validatePortMappings(self, portMappings):
        containerPorts = set()
        for mapping in portMappings:
            containerPort, hostPort = mapping.split(':')
            hostPortNum = int(hostPort)
            if int(containerPort) > 65535 or hostPortNum > 65535:
                return False
            if containerPort in containerPorts and int(containerPort) !== hostPortNum:
                return False
            containerPorts.add(containerPort)
        return True
